import re
res=[]
# find text inside double quotes
for m in re.finditer(r'"([^"]{10,200})"', s):
    inside=m.group(1)
    # filter Arabic letters presence
    if re.search(r'[\u0600-\u06FF]', inside):
        res.append((m.start(1), m.end(1), inside))
# find between Arabic brackets ﴿ ... ﴾
for m in re.finditer(r'﴿([^﴾]{10,400})﴾', s):
    inside=m.group(1)
    if re.search(r'[\u0600-\u06FF]', inside):
        res.append((m.start(1), m.end(1), inside))
# also occurrences after قالوا: without quotes, capture phrase starting with إِنَّا or إِنَّكَ up to ) or *
for m in re.finditer(r'(إِنَّا[^\n\(\*]{10,300})', s):
    res.append((m.start(1), m.end(1), m.group(1)))
# deduplicate by span
res_sorted=sorted(res, key=lambda x:x[0])
for a,b,t in res_sorted:
    print(a,b,t[:120])
